/**
 * Sidebar Status Configuration System
 *
 * Centralized configuration for workspace/session statuses, priorities, and visual styling.
 * Design philosophy: Make it easy to iterate on colors and priorities without touching component code.
 *
 * @see src/features/session/types.ts for SessionStatus type definition
 */

import type { Workspace } from "@/features/workspace/types";
import type { WorkspaceStatus } from "@shared/enums";

/**
 * Display status extends SessionStatus with derived states.
 * 'unread' is derived from needs_response / needs_plan_response session status.
 */
export type DisplayStatus = "idle" | "working" | "error" | "unread";

/**
 * Priority levels for sorting (higher = more urgent)
 */
export enum StatusPriority {
  ERROR = 4, // Critical - something broke
  UNREAD = 3, // Important - needs review / response
  WORKING = 2, // Active - in progress
  IDLE = 0, // Dormant - no activity
}

/**
 * Visual configuration for each status
 *
 * Design System:
 * - badge: Color for notification badges (collapsed sidebar)
 * - border: Border/glow color for active states
 * - text: Text color for status labels
 * - bg: Background color for sections/cards
 *
 * Color Semantics:
 * 🔴 Red (error) = Critical, blocking, needs immediate action
 * 🟡 Amber (unread) = Important, needs attention when ready
 * 🟢 Green (working) = Active, positive, making progress
 * 🟣 Purple (compacting) = Transient, maintenance, ignore
 * ⚪ Gray (idle) = Dormant, background, low priority
 */
export interface StatusConfig {
  priority: StatusPriority;
  label: string;
  labelActive: string; // Present continuous form (e.g., "Working...")
  badge: string; // Tailwind classes for badge
  border: string; // Tailwind classes for border/glow
  text: string; // Tailwind classes for text
  bg: string; // Tailwind classes for background
  pulse?: boolean; // Whether to animate/pulse
}

/**
 * Status configuration map
 *
 * IMPORTANT: To change colors, edit this object (no component changes needed)
 */
export const STATUS_CONFIG: Record<DisplayStatus, StatusConfig> = {
  error: {
    priority: StatusPriority.ERROR,
    label: "Error",
    labelActive: "Error",
    badge: "bg-destructive text-destructive-foreground",
    border: "border-destructive/60",
    text: "text-destructive",
    bg: "bg-destructive/10",
    pulse: true,
  },
  unread: {
    priority: StatusPriority.UNREAD,
    label: "Needs Response",
    labelActive: "Awaiting Input",
    badge: "bg-status-unread text-status-unread-fg",
    border: "border-status-unread/60",
    text: "text-status-unread",
    bg: "bg-status-unread/10",
    pulse: false,
  },
  working: {
    priority: StatusPriority.WORKING,
    label: "Working",
    labelActive: "Working...",
    badge: "bg-primary text-primary-foreground",
    border: "border-primary/60",
    text: "text-primary",
    bg: "bg-primary/10",
    pulse: true,
  },
  idle: {
    priority: StatusPriority.IDLE,
    label: "Idle",
    labelActive: "Idle",
    badge: "bg-muted text-muted-foreground",
    border: "border-muted",
    text: "text-muted-foreground",
    bg: "bg-muted/30",
    pulse: false,
  },
};

// ── Workflow Status (Linear-style) ────────────────────────────────────────
// Separate from DisplayStatus which shows real-time agent activity.
// Rendered as a small icon to the left of the workspace title.

export interface WorkflowStatusConfig {
  label: string;
  color: string;
}

export const WORKFLOW_STATUS_CONFIG: Record<WorkspaceStatus, WorkflowStatusConfig> = {
  backlog: { label: "Backlog", color: "text-muted-foreground" },
  "in-progress": { label: "In Progress", color: "text-status-in-progress" },
  "in-review": { label: "In Review", color: "text-status-in-review" },
  done: { label: "Done", color: "text-status-done" },
  canceled: { label: "Canceled", color: "text-muted-foreground" },
};

/**
 * Derive display status from workspace data
 *
 * Priority logic:
 * 1. Error — session in error state
 * 2. Unread — agent needs user response (needs_response / needs_plan_response)
 * 3. Working — agent actively processing
 * 4. Idle — dormant
 *
 * @param workspace Workspace data with session info
 * @returns Derived display status for UI rendering
 */
export function getDisplayStatus(workspace: Workspace): DisplayStatus {
  const status = workspace.session_status;

  if (status === "error") return "error";
  if (status === "needs_response" || status === "needs_plan_response") return "unread";
  if (status === "working") return "working";
  return "idle";
}

/**
 * Check if workspace needs user attention.
 * In V2, attention state is derived from session_status (needs_response / needs_plan_response).
 */
export function getUnreadCount(workspace: Workspace): number {
  const status = workspace.session_status;
  return status === "needs_response" || status === "needs_plan_response" ? 1 : 0;
}

/**
 * Sort workspaces by status priority
 * Higher priority statuses appear first
 *
 * @param workspaces Array of workspaces to sort
 * @returns Sorted array (original array not mutated)
 */
export function sortByStatusPriority<T extends Workspace>(workspaces: T[]): T[] {
  return [...workspaces].sort((a, b) => {
    const statusA = getDisplayStatus(a);
    const statusB = getDisplayStatus(b);
    const priorityA = STATUS_CONFIG[statusA].priority;
    const priorityB = STATUS_CONFIG[statusB].priority;

    // Higher priority first
    if (priorityA !== priorityB) {
      return priorityB - priorityA;
    }

    // Same priority: sort by latest activity (most recent first)
    const timeA = new Date(a.updated_at).getTime();
    const timeB = new Date(b.updated_at).getTime();
    return timeB - timeA;
  });
}

/**
 * Group workspaces by display status
 * Used for rendering section headers in expanded sidebar
 *
 * @param workspaces Array of workspaces to group
 * @returns Object with status as keys, workspace arrays as values
 */
export function groupByStatus<T extends Workspace>(
  workspaces: T[]
): Partial<Record<DisplayStatus, T[]>> {
  const groups: Partial<Record<DisplayStatus, T[]>> = {};

  workspaces.forEach((workspace) => {
    const status = getDisplayStatus(workspace);
    if (!groups[status]) {
      groups[status] = [];
    }
    groups[status]!.push(workspace);
  });

  return groups;
}

/**
 * Get aggregate status counts for a repository
 * Used for collapsed sidebar status indicators
 *
 * @param workspaces Workspaces in a repository
 * @returns Count of each status type
 */
export function getStatusCounts(workspaces: Workspace[]): Record<DisplayStatus, number> {
  const counts: Record<DisplayStatus, number> = {
    error: 0,
    unread: 0,
    working: 0,
    idle: 0,
  };

  workspaces.forEach((workspace) => {
    const status = getDisplayStatus(workspace);
    counts[status]++;
  });

  return counts;
}

/**
 * Get total unread count for a repository
 * Sums unread across all workspaces
 */
export function getRepoUnreadCount(workspaces: Workspace[]): number {
  return workspaces.reduce((sum, workspace) => {
    return sum + getUnreadCount(workspace);
  }, 0);
}

/**
 * Get highest priority status for a repository
 * Used for collapsed sidebar badge color
 *
 * @param workspaces Workspaces in a repository
 * @returns The highest priority status present
 */
export function getRepoPriorityStatus(workspaces: Workspace[]): DisplayStatus {
  let highestPriority = StatusPriority.IDLE;
  let highestStatus: DisplayStatus = "idle";

  workspaces.forEach((workspace) => {
    const status = getDisplayStatus(workspace);
    const priority = STATUS_CONFIG[status].priority;

    if (priority > highestPriority) {
      highestPriority = priority;
      highestStatus = status;
    }
  });

  return highestStatus;
}

import { Plus, ChevronRight, GitPullRequest } from "lucide-react";
import { AnimatePresence, m, useReducedMotion } from "framer-motion";
import { SidebarMenuItem } from "@/components/ui/sidebar";
import { Collapsible, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
import { cn } from "@/shared/lib/utils";
import { getCleanRepoName } from "../lib/utils";
import { sortByStatusPriority } from "../lib/status";
import type { RepositoryItemProps } from "../model/types";
import { WorkspaceItem } from "./WorkspaceItem";
import { RepoAvatar } from "./RepoAvatar";
import { SidebarRow, SidebarRowMain, SidebarRowIconSlot, SidebarRowRight } from "./SidebarRow";
import { OpenDevsRepositoryBanner } from "./OpenDevsRepositoryBanner";

/** Check if a git remote URL points to GitHub */
function isGitHubUrl(url: string | null | undefined): boolean {
  return !!url && url.includes("github.com");
}

/**
 * RepositoryItem — V2: Jony Ive
 *
 * Layout:
 *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 *     └── [+ New workspace]
 *     └── WorkspaceItem[]
 *
 * The repo header uses text-secondary (B0B0B0) 14px medium.
 * Action icons: text-muted (#787878), appear on hover.
 */
export function RepositoryItem({
  repository,
  isCollapsed,
  selectedWorkspaceId,
  onToggleCollapse,
  onWorkspaceClick,
  onNewWorkspace,
  onNewWorkspaceFromGitHub,
  onArchive,
  onStatusChange,
  diffStatsMap,
  sidebarExpanded,
}: RepositoryItemProps) {
  const reduceMotion = useReducedMotion();
  const repoName = getCleanRepoName(repository.repo_name);
  // Detect the opendevs repo by clean name (works for "opendevs" or "org/opendevs")
  const isOpenDevs = repoName === "opendevs";
  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;

  return (
    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
      <SidebarMenuItem
        data-state={isCollapsed ? "closed" : "open"}
        className="group/repository-item relative"
      >
        <CollapsibleTrigger asChild>
          <SidebarRow
            variant="repo"
            role="button"
            aria-label={`Toggle ${repoName} workspaces`}
            className="cursor-grab"
          >
            <SidebarRowMain className="gap-2">
              <div className="relative flex-shrink-0">
                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
                  <RepoAvatar repoName={repository.repo_name} />
                </div>
                <ChevronRight
                  className={cn(
                    "absolute inset-0 m-auto h-4 w-4",
                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
                    !isCollapsed && "rotate-90"
                  )}
                />
              </div>
              <span className="text-text-secondary truncate text-sm font-medium">{repoName}</span>
              {workspaceCount > 0 && (
                <span className="text-text-muted text-xs tabular-nums">{workspaceCount}</span>
              )}
            </SidebarRowMain>
            {sidebarExpanded && (
              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <button
                        type="button"
                        aria-label={`New workspace from PR or branch in ${repoName}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          onNewWorkspaceFromGitHub(repository.repo_id);
                        }}
                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                      >
                        <GitPullRequest className="h-4 w-4" />
                      </button>
                    </TooltipTrigger>
                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
                  </Tooltip>
                )}
                <Tooltip>
                  <TooltipTrigger asChild>
                    <button
                      type="button"
                      aria-label={`New workspace in ${repoName}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        onNewWorkspace(repository.repo_id);
                      }}
                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                    >
                      <Plus className="h-4 w-4" />
                    </button>
                  </TooltipTrigger>
                  <TooltipContent side="bottom">New workspace</TooltipContent>
                </Tooltip>
              </SidebarRowRight>
            )}
          </SidebarRow>
        </CollapsibleTrigger>
      </SidebarMenuItem>
      <AnimatePresence initial={false}>
        {!isCollapsed && (
          <m.ul
            key="workspace-list"
            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
            className="flex min-w-0 flex-col overflow-hidden"
          >
            {sidebarExpanded &&
              (() => {
                const sortedWorkspaces = sortByStatusPriority(
                  repository.workspaces.filter((w) => w.state !== "archived")
                );

                return (
                  <>
                    {/* OpenDevs repo gets a special contribution nudge banner */}
                    {isOpenDevs && (
                      <m.li
                        initial={reduceMotion ? false : { opacity: 0, y: -4 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{
                          duration: 0.22,
                          ease: [0.165, 0.84, 0.44, 1],
                          delay: reduceMotion ? 0 : 0.02,
                        }}
                      >
                        <OpenDevsRepositoryBanner
                          onNewWorkspace={() => onNewWorkspace(repository.repo_id)}
                        />
                      </m.li>
                    )}

                    {sortedWorkspaces.length === 0 && (
                      <m.li
                        initial={reduceMotion ? false : { opacity: 0, y: -4 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{
                          duration: 0.18,
                          ease: [0.165, 0.84, 0.44, 1],
                          delay: reduceMotion ? 0 : 0.03,
                        }}
                      >
                        <SidebarRow
                          variant="action"
                          asChild
                          onClick={() => onNewWorkspace(repository.repo_id)}
                          className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
                        >
                          <button type="button">
                            <SidebarRowMain>
                              <SidebarRowIconSlot>
                                <Plus className="h-4 w-4" />
                              </SidebarRowIconSlot>
                              <span className="font-normal">New workspace</span>
                            </SidebarRowMain>
                          </button>
                        </SidebarRow>
                      </m.li>
                    )}

                    {sortedWorkspaces.map((workspace, index) => (
                      <m.li
                        key={workspace.id}
                        initial={reduceMotion ? false : { opacity: 0, y: -4 }}
                        animate={{ opacity: 1, y: 0 }}
                        transition={{
                          duration: 0.18,
                          ease: [0.165, 0.84, 0.44, 1],
                          delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
                        }}
                      >
                        <WorkspaceItem
                          workspace={workspace}
                          isActive={workspace.id === selectedWorkspaceId}
                          diffStats={diffStatsMap?.[workspace.id]}
                          onClick={onWorkspaceClick}
                          onArchive={onArchive}
                          onStatusChange={onStatusChange}
                        />
                      </m.li>
                    ))}
                  </>
                );
              })()}
          </m.ul>
        )}
      </AnimatePresence>
    </Collapsible>
  );
}

