 2→import { persist } from "zustand/middleware";
 3→
 4→interface SidebarState {
 5→  // Sidebar-specific state
 6→  collapsedRepos: Set<string>;
 7→  toggleRepoCollapse: (repoId: string) => void;
 8→
 9→  // Repos where user expanded the "Show more" stale workspaces
10→  expandedOldWorkspaces: Set<string>;
11→  toggleOldWorkspaces: (repoId: string) => void;
12→
13→  // Repository ordering
14→  repositoryOrder: string[];
15→  setRepositoryOrder: (order: string[]) => void;
