20→  persist(
21→    (set, get) => ({
22→      // Existing state
23→      collapsedRepos: new Set(),
24→      toggleRepoCollapse: (repoId) =>
25→        set((state) => {
26→          const newCollapsed = new Set(state.collapsedRepos);
27→          if (newCollapsed.has(repoId)) {
28→            newCollapsed.delete(repoId);
29→          } else {
30→            newCollapsed.add(repoId);
31→          }
32→          return { collapsedRepos: newCollapsed };
33→        }),
34→
35→      // Stale workspace expansion (per-repo)
36→      expandedOldWorkspaces: new Set(),
37→      toggleOldWorkspaces: (repoId) =>
38→        set((state) => {
39→          const next = new Set(state.expandedOldWorkspaces);
40→          if (next.has(repoId)) {
41→            next.delete(repoId);
42→          } else {
43→            next.add(repoId);
44→          }
45→          return { expandedOldWorkspaces: next };
46→        }),
47→
48→      // Repository ordering
49→      repositoryOrder: [],
50→
51→      setRepositoryOrder: (order) => set({ repositoryOrder: order }),
52→
53→      /**
54→       * Reorder repositories based on user preferences
55→       * Unordered repos appear at the end in their original order
56→       */
57→      reorderRepositories: (repos) => {
58→        const { repositoryOrder } = get();
59→
60→        // If no custom order, return as-is
61→        if (repositoryOrder.length === 0) return repos;
62→
63→        // Create lookup map for O(1) access
64→        const orderMap = new Map(repositoryOrder.map((id, idx) => [id, idx]));
65→
66→        return [...repos].sort((a, b) => {
