/**
 * Sidebar utility functions
 * Extracted from AppSidebar.tsx for better organization
 *
 * For status-related utilities (colors, priorities, sorting),
 * @see status.ts
 */

import type { Workspace } from "@/features/workspace/types";
import { getDisplayStatus } from "./status";

/**
 * Get repository initials for display
 * @param repoName - Repository name (e.g., "box-ide" or "owner/repo")
 * @returns Uppercase initials (e.g., "BI" or "OR")
 */
export function getRepoInitials(repoName: string): string {
  const parts = repoName.split(/[-_\s]/);
  if (parts.length >= 2) {
    return (parts[0][0] + parts[1][0]).toUpperCase();
  }
  return repoName.slice(0, 2).toUpperCase();
}

/**
 * Get color scheme for repository badge based on name hash
 * @param repoName - Repository name
 * @returns Semantic design token classes
 */
export function getRepoColor(repoName: string): { bg: string; text: string } {
  const hash = repoName.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0);
  // Use semantic tokens so colors follow the design system theme.
  const schemes = [
    { bg: "bg-primary/20", text: "text-primary" },
    { bg: "bg-secondary/30", text: "text-secondary-foreground" },
    { bg: "bg-accent/30", text: "text-accent-foreground" },
    { bg: "bg-muted", text: "text-muted-foreground" },
    { bg: "bg-sidebar-accent", text: "text-sidebar-foreground" },
  ];
  return schemes[hash % schemes.length];
}

/**
 * Clean repository display name by removing username prefix
 * @param repoName - Full repository name (e.g., "zvadaadam/overlay" or "box-ide")
 * @returns Clean display name (e.g., "overlay" or "box-ide")
 */
export function getCleanRepoName(repoName: string): string {
  // Check if repo name contains username prefix (format: "username/repo")
  const parts = repoName.split("/");
  if (parts.length === 2) {
    // Return just the repo name without username
    return parts[1];
  }
  // Return as-is if no prefix
  return repoName;
}

/**
 * Smart display name for workspace sidebar row.
 *
 * Priority:
 *   1. workspace.title — AI-generated summary (after first turn), PR title, or user rename
 *   2. workspace.slug  — celestial name (clean, human-readable)
 *   3. workspace.git_branch — raw branch name as absolute fallback
 *   4. "New workspace" — nothing available yet (during early init)
 */
export function getWorkspaceDisplayName(workspace: {
  title: string | null;
  slug: string;
  git_branch: string | null;
}): string {
  if (workspace.title) return workspace.title;
  if (workspace.slug) return workspace.slug;
  return workspace.git_branch || "New workspace";
}

/**
 * Secondary line text for the workspace sidebar row.
 *
 * When a title is displayed (AI-generated, PR title, or user rename),
 * show the slug as context. When slug IS the primary name, return null.
 */
export function getWorkspaceSecondaryText(workspace: {
  title: string | null;
  slug: string;
}): string | null {
  // Show slug as secondary only when title is the primary display name
  if (workspace.title && workspace.slug) return workspace.slug;
  return null;
}

// ── Recency-based workspace splitting ────────────────────────────────────

/** Minimum workspace count before stale hiding kicks in */
const STALE_HIDE_MIN_WORKSPACES = 5;
/** Always show at least this many workspaces (backfill from stale if needed) */
const MIN_VISIBLE = 3;
/** Don't bother with "Show N more" if fewer than this would be hidden */
const MIN_STALE_TO_HIDE = 2;
/** Days after which an idle workspace is considered stale */
const STALE_DAYS = 7;

/**
 * Split workspaces into visible and stale (hidden by default).
 *
 * Rules:
 * - Only activates when there are >= STALE_HIDE_MIN_WORKSPACES
 * - Active workspaces (working, error, unread) are always visible
 * - The currently selected workspace is always visible
 * - Idle workspaces updated > STALE_DAYS ago are stale
 * - Always shows at least MIN_VISIBLE workspaces (backfills from stale)
 * - Never hides fewer than MIN_STALE_TO_HIDE (avoids "Show 1 more")
 *
 * @returns [visible, stale] — two arrays, already in the same order as input
 */
export function splitByRecency<T extends Workspace>(
  workspaces: T[],
  selectedWorkspaceId: string | undefined
): [visible: T[], stale: T[]] {
  if (workspaces.length < STALE_HIDE_MIN_WORKSPACES) {
    return [workspaces, []];
  }

  const cutoff = Date.now() - STALE_DAYS * 24 * 60 * 60 * 1000;
  const visible: T[] = [];
  const stale: T[] = [];

  for (const ws of workspaces) {
    const status = getDisplayStatus(ws);
    const isActive = status !== "idle";
    const isSelected = ws.id === selectedWorkspaceId;
    const isRecent = new Date(ws.updated_at).getTime() >= cutoff;

    if (isActive || isSelected || isRecent) {
      visible.push(ws);
    } else {
      stale.push(ws);
    }
  }

  // Backfill from stale so the repo never looks empty
  while (visible.length < MIN_VISIBLE && stale.length > 0) {
    visible.push(stale.shift()!);
  }

  // Don't bother hiding if only 1 would be hidden ("Show 1 more" is silly)
  if (stale.length < MIN_STALE_TO_HIDE) {
    return [workspaces, []];
  }

  return [visible, stale];
}

import { Plus, ChevronRight, ChevronDown, GitPullRequest } from "lucide-react";
import { AnimatePresence, m, useReducedMotion } from "framer-motion";
import { SidebarMenuItem } from "@/components/ui/sidebar";
import { Collapsible, CollapsibleTrigger } from "@/components/ui/collapsible";
import { Tooltip, TooltipTrigger, TooltipContent } from "@/components/ui/tooltip";
import { cn } from "@/shared/lib/utils";
import { getCleanRepoName, splitByRecency } from "../lib/utils";
import { sortByStatusPriority } from "../lib/status";
import { useSidebarStore } from "../store/sidebarStore";
import type { RepositoryItemProps } from "../model/types";
import type { Workspace, DiffStats, RepoGroup } from "@/shared/types";
import type { WorkspaceStatus } from "@shared/enums";
import { WorkspaceItem } from "./WorkspaceItem";
import { RepoAvatar } from "./RepoAvatar";
import { SidebarRow, SidebarRowMain, SidebarRowIconSlot, SidebarRowRight } from "./SidebarRow";
import { OpenDevsRepositoryBanner } from "./OpenDevsRepositoryBanner";

/** Check if a git remote URL points to GitHub */
function isGitHubUrl(url: string | null | undefined): boolean {
  return !!url && url.includes("github.com");
}

/**
 * RepositoryItem — V2: Jony Ive
 *
 * Layout:
 *   [Badge 20×20] [RepoName]  ...  [PR] [+] [⋯]  (hover-reveal actions)
 *     └── [+ New workspace]
 *     └── WorkspaceItem[]
 *
 * The repo header uses text-secondary (B0B0B0) 14px medium.
 * Action icons: text-muted (#787878), appear on hover.
 */
export function RepositoryItem({
  repository,
  isCollapsed,
  selectedWorkspaceId,
  onToggleCollapse,
  onWorkspaceClick,
  onNewWorkspace,
  onNewWorkspaceFromGitHub,
  onArchive,
  onStatusChange,
  diffStatsMap,
  sidebarExpanded,
}: RepositoryItemProps) {
  const reduceMotion = useReducedMotion();
  const repoName = getCleanRepoName(repository.repo_name);
  // Detect the opendevs repo by clean name (works for "opendevs" or "org/opendevs")
  const isOpenDevs = repoName === "opendevs";
  const workspaceCount = repository.workspaces.filter((w) => w.state !== "archived").length;

  return (
    <Collapsible open={!isCollapsed} onOpenChange={() => onToggleCollapse()}>
      <SidebarMenuItem
        data-state={isCollapsed ? "closed" : "open"}
        className="group/repository-item relative"
      >
        <CollapsibleTrigger asChild>
          <SidebarRow
            variant="repo"
            role="button"
            aria-label={`Toggle ${repoName} workspaces`}
            className="cursor-grab"
          >
            <SidebarRowMain className="gap-2">
              <div className="relative flex-shrink-0">
                <div className="transition-opacity duration-150 group-hover/repository-item:opacity-0">
                  <RepoAvatar repoName={repository.repo_name} />
                </div>
                <ChevronRight
                  className={cn(
                    "absolute inset-0 m-auto h-4 w-4",
                    "text-text-muted opacity-0 transition-[transform,opacity] duration-150 group-hover/repository-item:opacity-100",
                    !isCollapsed && "rotate-90"
                  )}
                />
              </div>
              <span className="text-text-secondary truncate text-sm font-medium">{repoName}</span>
              {workspaceCount > 0 && (
                <span className="text-text-muted text-xs tabular-nums">{workspaceCount}</span>
              )}
            </SidebarRowMain>
            {sidebarExpanded && (
              <SidebarRowRight className="gap-2 opacity-0 transition-opacity duration-150 group-hover/repository-item:opacity-100">
                {isGitHubUrl(repository.git_origin_url) && onNewWorkspaceFromGitHub && (
                  <Tooltip>
                    <TooltipTrigger asChild>
                      <button
                        type="button"
                        aria-label={`New workspace from PR or branch in ${repoName}`}
                        onClick={(e) => {
                          e.stopPropagation();
                          onNewWorkspaceFromGitHub(repository.repo_id);
                        }}
                        className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                      >
                        <GitPullRequest className="h-4 w-4" />
                      </button>
                    </TooltipTrigger>
                    <TooltipContent side="bottom">New from PR or branch</TooltipContent>
                  </Tooltip>
                )}
                <Tooltip>
                  <TooltipTrigger asChild>
                    <button
                      type="button"
                      aria-label={`New workspace in ${repoName}`}
                      onClick={(e) => {
                        e.stopPropagation();
                        onNewWorkspace(repository.repo_id);
                      }}
                      className="text-text-muted hover:text-text-tertiary cursor-pointer [&_*]:cursor-pointer"
                    >
                      <Plus className="h-4 w-4" />
                    </button>
                  </TooltipTrigger>
                  <TooltipContent side="bottom">New workspace</TooltipContent>
                </Tooltip>
              </SidebarRowRight>
            )}
          </SidebarRow>
        </CollapsibleTrigger>
      </SidebarMenuItem>
      <AnimatePresence initial={false}>
        {!isCollapsed && (
          <m.ul
            key="workspace-list"
            initial={reduceMotion ? false : { height: 0, opacity: 0 }}
            animate={{ height: "auto", opacity: 1 }}
            exit={reduceMotion ? { opacity: 0 } : { height: 0, opacity: 0 }}
            transition={{ duration: 0.22, ease: [0.165, 0.84, 0.44, 1] }}
            className="flex min-w-0 flex-col overflow-hidden"
          >
            {sidebarExpanded && (
              <RepositoryWorkspaceList
                repository={repository}
                isOpenDevs={isOpenDevs}
                selectedWorkspaceId={selectedWorkspaceId}
                diffStatsMap={diffStatsMap}
                reduceMotion={reduceMotion}
                onNewWorkspace={onNewWorkspace}
                onWorkspaceClick={onWorkspaceClick}
                onArchive={onArchive}
                onStatusChange={onStatusChange}
              />
            )}
          </m.ul>
        )}
      </AnimatePresence>
    </Collapsible>
  );
}

// ── Inner list with stale-workspace collapsing ───────────────────────────

interface RepositoryWorkspaceListProps {
  repository: RepoGroup;
  isOpenDevs: boolean;
  selectedWorkspaceId: string | null;
  diffStatsMap?: Record<string, DiffStats>;
  reduceMotion: boolean | null;
  onNewWorkspace: (repoId?: string) => void;
  onWorkspaceClick: (workspace: Workspace) => void;
  onArchive?: (workspaceId: string) => void;
  onStatusChange?: (workspaceId: string, status: WorkspaceStatus) => void;
}

function RepositoryWorkspaceList({
  repository,
  isOpenDevs,
  selectedWorkspaceId,
  diffStatsMap,
  reduceMotion,
  onNewWorkspace,
  onWorkspaceClick,
  onArchive,
  onStatusChange,
}: RepositoryWorkspaceListProps) {
  const isExpanded = useSidebarStore((s) => s.expandedOldWorkspaces.has(repository.repo_id));
  const toggleOldWorkspaces = useSidebarStore((s) => s.toggleOldWorkspaces);

  const sortedWorkspaces = sortByStatusPriority(
    repository.workspaces.filter((w) => w.state !== "archived")
  );

  const [visible, stale] = splitByRecency(sortedWorkspaces, selectedWorkspaceId ?? undefined);
  const hasStale = stale.length > 0;
  const displayedWorkspaces = hasStale && !isExpanded ? visible : sortedWorkspaces;

  return (
    <>
      {isOpenDevs && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.22,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : 0.02,
          }}
        >
          <OpenDevsRepositoryBanner onNewWorkspace={() => onNewWorkspace(repository.repo_id)} />
        </m.li>
      )}

      {sortedWorkspaces.length === 0 && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.18,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : 0.03,
          }}
        >
          <SidebarRow
            variant="action"
            asChild
            onClick={() => onNewWorkspace(repository.repo_id)}
            className="text-text-tertiary hover:text-text-secondary w-full text-left text-base"
          >
            <button type="button">
              <SidebarRowMain>
                <SidebarRowIconSlot>
                  <Plus className="h-4 w-4" />
                </SidebarRowIconSlot>
                <span className="font-normal">New workspace</span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}

      {displayedWorkspaces.map((workspace, index) => (
        <m.li
          key={workspace.id}
          initial={reduceMotion ? false : { opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{
            duration: 0.18,
            ease: [0.165, 0.84, 0.44, 1],
            delay: reduceMotion ? 0 : Math.min(0.05 + index * 0.025, 0.12),
          }}
        >
          <WorkspaceItem
            workspace={workspace}
            isActive={workspace.id === selectedWorkspaceId}
            diffStats={diffStatsMap?.[workspace.id]}
            onClick={onWorkspaceClick}
            onArchive={onArchive}
            onStatusChange={onStatusChange}
          />
        </m.li>
      ))}

      {hasStale && (
        <m.li
          initial={reduceMotion ? false : { opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.15, ease: [0.165, 0.84, 0.44, 1] }}
        >
          <SidebarRow
            variant="action"
            asChild
            className="text-text-muted hover:text-text-secondary w-full text-left"
          >
            <button
              type="button"
              onClick={() => toggleOldWorkspaces(repository.repo_id)}
            >
              <SidebarRowMain>
                <SidebarRowIconSlot>
                  <ChevronDown
                    className={cn(
                      "h-3.5 w-3.5 transition-transform duration-150",
                      isExpanded && "rotate-180"
                    )}
                  />
                </SidebarRowIconSlot>
                <span className="text-xs font-medium">
                  {isExpanded ? "Show less" : `Show ${stale.length} more`}
                </span>
              </SidebarRowMain>
            </button>
          </SidebarRow>
        </m.li>
      )}
    </>
  );
}

