  2→ * Sidebar utility functions
  3→ * Extracted from AppSidebar.tsx for better organization
  4→ *
  5→ * For status-related utilities (colors, priorities, sorting),
  6→ * @see status.ts
  7→ */
  8→
  9→import type { Workspace } from "@/features/workspace/types";
