 11→
 12→/**
 13→ * Get repository initials for display
 14→ * @param repoName - Repository name (e.g., "box-ide" or "owner/repo")
 15→ * @returns Uppercase initials (e.g., "BI" or "OR")
 16→ */
 17→export function getRepoInitials(repoName: string): string {
 18→  const parts = repoName.split(/[-_\s]/);
 19→  if (parts.length >= 2) {
 20→    return (parts[0][0] + parts[1][0]).toUpperCase();
 21→  }
 22→  return repoName.slice(0, 2).toUpperCase();
 23→}
 24→
 25→/**
 26→ * Get color scheme for repository badge based on name hash
 27→ * @param repoName - Repository name
 28→ * @returns Semantic design token classes
 29→ */
 30→export function getRepoColor(repoName: string): { bg: string; text: string } {
 31→  const hash = repoName.split("").reduce((acc, char) => acc + char.charCodeAt(0), 0);
 32→  // Use semantic tokens so colors follow the design system theme.
 33→  const schemes = [
 34→    { bg: "bg-primary/20", text: "text-primary" },
 35→    { bg: "bg-secondary/30", text: "text-secondary-foreground" },
 36→    { bg: "bg-accent/30", text: "text-accent-foreground" },
 37→    { bg: "bg-muted", text: "text-muted-foreground" },
 38→    { bg: "bg-sidebar-accent", text: "text-sidebar-foreground" },
 39→  ];
 40→  return schemes[hash % schemes.length];
 41→}
 42→
 43→/**
 44→ * Clean repository display name by removing username prefix
 45→ * @param repoName - Full repository name (e.g., "zvadaadam/overlay" or "box-ide")
 46→ * @returns Clean display name (e.g., "overlay" or "box-ide")
